#include <bits/stdc++.h>
using namespace std;
#define X '\n'
#define ll long long
/*Solution:
Initially, i tried a sliding window approach, but i encountered that the number contains
several zeros, so at the moment of dividing by 0, which mean that is at the "front" of the window
it causes the program to freeze...

When you're dividing by zero, it has a undefined behavior, the program will crash, 
that means runtime error, crash.


So, another approach to this problem is in every position we'll have the product of 13 adjacent 
digits, including the first one, the currently position, of course, and only
we'll carry the max product from all of the 13-size windows...

*/
int main() {
    ios::sync_with_stdio(false); cin.tie(nullptr);
    string num ="";
    ll window_size = 13;
    ll mx = LLONG_MIN;
    for (int i = 0; i <= num.length()-window_size; i++){
        ll current = 1;
        for (auto j = i; j < i + window_size; j++){
            current *= (num[j]-'0');
        }
        mx = max(mx,current);
    }
    cout << mx;
    return 0;
}